const API_BASE_URL = 'http://localhost:5000';

const angleSlider = document.getElementById('angle');
const velocitySlider = document.getElementById('velocity');
const gravitySlider = document.getElementById('gravity');
const angleValue = document.getElementById('angleValue');
const velocityValue = document.getElementById('velocityValue');
const gravityValue = document.getElementById('gravityValue');
const includeFormulaCheckbox = document.getElementById('includeFormula');
const simulateBtn = document.getElementById('simulateBtn');
const speakBtn = document.getElementById('speakBtn');
const canvas = document.getElementById('trajectoryCanvas');
const ctx = canvas.getContext('2d');
const audioPlayer = document.getElementById('audioPlayer');

let currentTrajectory = [];
let currentExplanation = '';
let currentAudioUrl = '';

angleSlider.addEventListener('input', () => {
    angleValue.textContent = angleSlider.value;
});

velocitySlider.addEventListener('input', () => {
    velocityValue.textContent = velocitySlider.value;
});

gravitySlider.addEventListener('input', () => {
    gravityValue.textContent = gravitySlider.value;
});

simulateBtn.addEventListener('click', runSimulation);
speakBtn.addEventListener('click', playAudio);

async function runSimulation() {
    const angle = parseFloat(angleSlider.value);
    const velocity = parseFloat(velocitySlider.value);
    const gravity = parseFloat(gravitySlider.value);
    const includeFormula = includeFormulaCheckbox.checked;

    simulateBtn.textContent = 'Loading...';
    simulateBtn.disabled = true;

    try {
        const response = await fetch(`${API_BASE_URL}/api/simulation`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                angle: angle,
                velocity: velocity,
                gravity: gravity,
                include_formula: includeFormula
            })
        });

        const data = await response.json();

        if (data.error) {
            console.error('API Error:', data.error);
            document.getElementById('explanationText').textContent = `Error: ${data.error}`;
            return;
        }

        currentTrajectory = data.trajectory || [];
        currentExplanation = data.explanation_text || '';
        currentAudioUrl = data.speech_audio_url || '';

        document.getElementById('maxHeight').textContent = data.max_height ? `${data.max_height.toFixed(2)} m` : '-';
        document.getElementById('range').textContent = data.range ? `${data.range.toFixed(2)} m` : '-';
        document.getElementById('timeOfFlight').textContent = data.time_of_flight ? `${data.time_of_flight.toFixed(2)} s` : '-';
        document.getElementById('explanationText').textContent = currentExplanation;

        drawTrajectory(currentTrajectory, angle, velocity, gravity);

        if (currentAudioUrl) {
            audioPlayer.src = currentAudioUrl;
            audioPlayer.style.display = 'block';
        } else {
            audioPlayer.style.display = 'none';
        }

    } catch (error) {
        console.error('Error:', error);
        document.getElementById('explanationText').textContent = `Error: ${error.message}`;
    } finally {
        simulateBtn.textContent = 'Run Simulation';
        simulateBtn.disabled = false;
    }
}

function playAudio() {
    if (currentAudioUrl) {
        audioPlayer.src = currentAudioUrl;
        audioPlayer.play();
    } else if (currentExplanation) {
        speakText(currentExplanation);
    } else {
        alert('Please run a simulation first');
    }
}

async function speakText(text) {
    try {
        const response = await fetch(`${API_BASE_URL}/api/simulation`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                text: text
            })
        });

        const data = await response.json();

        if (data.speech_audio_url) {
            audioPlayer.src = data.speech_audio_url;
            audioPlayer.style.display = 'block';
            audioPlayer.play();
        }
    } catch (error) {
        console.error('Error:', error);
    }
}

function drawTrajectory(trajectory, angle, velocity, gravity) {
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();

    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const width = rect.width;
    const height = rect.height;
    const padding = 50;

    ctx.clearRect(0, 0, width, height);

    ctx.strokeStyle = 'rgba(255, 255, 255, 0.2)';
    ctx.lineWidth = 1;

    ctx.beginPath();
    ctx.moveTo(padding, padding);
    ctx.lineTo(padding, height - padding);
    ctx.lineTo(width - padding, height - padding);
    ctx.stroke();

    ctx.fillStyle = '#aaa';
    ctx.font = '12px Arial';
    ctx.fillText('Y (m)', padding - 40, padding);
    ctx.fillText('X (m)', width - padding + 10, height - padding + 20);

    if (trajectory.length === 0) {
        ctx.fillStyle = '#fff';
        ctx.font = '16px Arial';
        ctx.textAlign = 'center';
        ctx.fillText('Run simulation to see trajectory', width / 2, height / 2);
        return;
    }

    let maxX = 0;
    let maxY = 0;
    trajectory.forEach(([x, y]) => {
        if (x > maxX) maxX = x;
        if (y > maxY) maxY = y;
    });

    maxX = maxX * 1.1;
    maxY = maxY * 1.1;

    const scaleX = (width - 2 * padding) / maxX;
    const scaleY = (height - 2 * padding) / maxY;

    const toCanvasX = (x) => padding + x * scaleX;
    const toCanvasY = (y) => height - padding - y * scaleY;

    const gridStepX = maxX / 5;
    const gridStepY = maxY / 5;

    ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
    ctx.fillStyle = '#666';
    ctx.font = '10px Arial';

    for (let i = 0; i <= 5; i++) {
        const xVal = i * gridStepX;
        const xPos = toCanvasX(xVal);

        ctx.beginPath();
        ctx.moveTo(xPos, padding);
        ctx.lineTo(xPos, height - padding);
        ctx.stroke();

        ctx.fillText(xVal.toFixed(1), xPos - 10, height - padding + 15);

        const yVal = i * gridStepY;
        const yPos = toCanvasY(yVal);

        ctx.beginPath();
        ctx.moveTo(padding, yPos);
        ctx.lineTo(width - padding, yPos);
        ctx.stroke();

        ctx.fillText(yVal.toFixed(1), padding - 35, yPos + 4);
    }

    const gradient = ctx.createLinearGradient(
        toCanvasX(0), toCanvasY(0),
        toCanvasX(maxX), toCanvasY(maxY)
    );
    gradient.addColorStop(0, '#00d4ff');
    gradient.addColorStop(1, '#7c3aed');

    ctx.strokeStyle = gradient;
    ctx.lineWidth = 3;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    ctx.beginPath();
    trajectory.forEach((point, index) => {
        const x = toCanvasX(point[0]);
        const y = toCanvasY(point[1]);
        if (index === 0) {
            ctx.moveTo(x, y);
        } else {
            ctx.lineTo(x, y);
        }
    });
    ctx.stroke();

    ctx.fillStyle = '#00d4ff';
    const startX = toCanvasX(0);
    const startY = toCanvasY(0);
    ctx.beginPath();
    ctx.arc(startX, startY, 6, 0, 2 * Math.PI);
    ctx.fill();

    ctx.fillStyle = '#7c3aed';
    const endPoint = trajectory[trajectory.length - 1];
    const endX = toCanvasX(endPoint[0]);
    const endY = toCanvasY(endPoint[1]);
    ctx.beginPath();
    ctx.arc(endX, endY, 6, 0, 2 * Math.PI);
    ctx.fill();

    ctx.fillStyle = '#fff';
    ctx.font = 'bold 12px Arial';
    ctx.fillText('Start', startX - 20, startY - 15);
    ctx.fillText('End', endX - 15, endY - 15);

    const peakIndex = Math.floor(trajectory.length / 2);
    const peakPoint = trajectory[peakIndex];
    const peakX = toCanvasX(peakPoint[0]);
    const peakY = toCanvasY(peakPoint[1]);

    ctx.fillStyle = '#ff6b6b';
    ctx.beginPath();
    ctx.arc(peakX, peakY, 5, 0, 2 * Math.PI);
    ctx.fill();
    ctx.fillText('Peak', peakX - 15, peakY - 12);
}

window.addEventListener('resize', () => {
    if (currentTrajectory.length > 0) {
        const angle = parseFloat(angleSlider.value);
        const velocity = parseFloat(velocitySlider.value);
        const gravity = parseFloat(gravitySlider.value);
        drawTrajectory(currentTrajectory, angle, velocity, gravity);
    }
});

