    font-size: 1.3rem;
    margin-bottom: 15px;
    color: #00d4ff;
}

#explanationText {
    line-height: 1.8;
    color: #e0e0e0;
    font-size: 1.1rem;
}

.audio-player {
    margin-top: 20px;
    padding-top: 20px;
    border-top: 1px solid rgba(255, 255, 255, 0.1);
}

#audioPlayer {
    width: 100%;
    max-width: 600px;
}

.loading {
    opacity: 0.7;
